document.addEventListener("DOMContentLoaded",function(){"use strict";var t=document.getElementById("input-value"),e=document.getElementById("input-base"),n=document.getElementById("calc-btn"),o=document.getElementById("reset-btn"),r=document.getElementById("result"),i=document.getElementById("result-bin"),d=document.getElementById("result-oct"),a=document.getElementById("result-dec"),u=document.getElementById("result-hex");n.addEventListener("click",function(){var n=t.value.trim(),o=parseInt(e.value,10);if(n){var l=parseInt(n,o);isNaN(l)||l<0?alert("入力値が正しくありません。選択した進数に合った値を入力してください。"):(i.textContent=l.toString(2),d.textContent=l.toString(8),a.textContent=l.toString(10),u.textContent=l.toString(16).toUpperCase(),r.hidden=!1,r.scrollIntoView({behavior:"smooth"}))}else alert("変換する値を入力してください。")}),t.addEventListener("input",function(){var n=t.value.trim(),o=parseInt(e.value,10);if(n){var l=parseInt(n,o);isNaN(l)||l<0?r.hidden=!0:(i.textContent=l.toString(2),d.textContent=l.toString(8),a.textContent=l.toString(10),u.textContent=l.toString(16).toUpperCase(),r.hidden=!1)}else r.hidden=!0}),e.addEventListener("change",function(){var n=t.value.trim();if(n){var o=parseInt(e.value,10),l=parseInt(n,o);!isNaN(l)&&l>=0&&(i.textContent=l.toString(2),d.textContent=l.toString(8),a.textContent=l.toString(10),u.textContent=l.toString(16).toUpperCase(),r.hidden=!1)}}),o.addEventListener("click",function(){t.value="",e.value="10",r.hidden=!0})});